import pytest
from <helper_fn> import api_client, create_patient, clinician_token

def test_post_allergy_intolerance_minimal_payload_boundary():
    client = api_client(token=clinician_token())
    patient_id = create_patient(client)
    minimal_payload = {
        "resourceType": "AllergyIntolerance",
        "patient": {"reference": f"Patient/{patient_id}"},
        "code": {"coding": [{"system": "http://snomed.info/sct", "code": "372687004", "display": "Amoxicillin"}]}
    }
    resp = client.post("/AllergyIntolerance", json=minimal_payload)
    assert resp.status_code == 201, (
        f"Minimal payload rejected with {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert "id" in body, "Response must include a server-assigned id"
